VALUES
  ('fire-eq-eng-moex-00853', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防設備師及消防設備士管理辦法規定，下列敘述何者錯誤？', '["不得有允諾他人假藉其名義執行業務之行為", "執行業務時，應備業務登記簿，至少應保存五年", "自取得證書日起每三年應接受講習一次或取得累計積分達一百六十分以上之訓練證明文件", "辦理技術研討活動或訓練之機關（構）、團體應於舉辦一個月前，檢附規定文件向中央主管機關申請 認可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00854', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編，防火門窗係指防火門及防火窗，其構造規定下列何者正確？', '["防火門窗周邊10公分範圍內之牆壁應以不燃材料建造", "防火門之門扇寬度應在90公分以上，高度應在180公分以上", "常時關閉式之防火門單一門扇面積不得超過3平方公尺", "防火門應朝室內方向開啟。但供住宅使用及宿舍寢室、旅館客房、醫院病房等連接走廊者，不在此限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00855', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依住宅用火災警報器設置辦法，住宅用火災警報器之安裝方式，下列敘述何者正確？', '["裝置於天花板或樓板者，警報器下端距離天花板或樓板50公分以內", "裝置於牆面者，距天花板或樓板下方15公分以上50公分以下", "距離出風口1公尺以上", "以裝置於居室出入口附近為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00856', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防焰性能認證實施要點，下列何者非屬於消防法第11條第1項規定之防焰物品？', '["面積為一點五平方公尺之門墊", "布質製窗簾（含布製一般窗簾，直葉式、橫葉式百葉窗簾）", "供舞台或攝影棚使用之布幕", "網目為十公釐之施工用帆布"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00857', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依避難器具支固器具及固定部之結構、強度計算及施工方法，固定部材料上使用錨定螺栓，若螺栓直徑 為1公分，試驗荷重 (設計拉拔荷重)為1000公斤力(kgf)，則鎖緊扭力為多少公斤力/公分(kgf/cm)？', '["60", "120", "240", "360"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00858', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品試驗方法及判定基準之規定，利用「可燃性固體」與「易燃性液體」之判斷基準，下 列歸類何者錯誤？', '["採閉杯式閃火點試驗方法時，閃火點溫度不大於40 ℃之固體試驗物品為易燃性固體", "水溶性液體閃火點如低於21℃者，為第一石油類", "水溶性液體閃火點如介於40℃至60℃者，為第二石油類", "水溶性液體閃火點如介於141℃至180℃者，為第四石油類"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00859', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，下列氣體狀態何者為符合本辦法 之可燃性高壓氣體？', '["溫度在攝氏三十五度時，表壓力達每平方公分十五公斤之壓縮氫氣", "在常用溫度下，表壓力達每平方公分五公斤之壓縮甲烷", "在常用溫度下，表壓力達每平方公分一點五公斤之壓縮乙炔氣", "在攝氏三十五度以下，表壓力達每平方公分一點五公斤之液化丙烷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00860', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，室內儲存場所儲存六類物品之數 量，如未達管制量五十倍者，下列儲存倉庫周圍保留空地寬度，何者符合規定？', '["達管制量六倍者，無保留空地", "達管制量十二倍者，無保留空地", "達管制量二十五倍者，保留空地寬度為一公尺", "達管制量四十倍者，保留空地寬度為三公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00861', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，以室外儲槽儲存閃火點在攝氏四十度以下第四類公共危險 物品之顯著滅火困難場所者，且設於岸壁、碼頭或其他類似之地區，並連接輸送設備者，如設置泡沫射 水槍滅火設備，下列何者有誤？', '["室外儲槽之幫浦設備等設於岸壁、碼頭或其他類似之地區時，泡沫射水槍應能防護該場所位於海面上 前端之水平距離十五公尺以內之海面", "距離注入口及其附屬之公共危險物品處理設備各部分之水平距離在三十公尺以內，其設置個數在二具 以上", "泡沫射水槍為移動式，設於無礙滅火活動及可啟動、操作之位置", "射水槍同時放射時，泡沫放射量為每分鐘一千九百公升以上，且其有效水平放射距離在三十公尺以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00862', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，建築物間設有過廊，如有效寬度在A公尺以下，連接建築 物之間距，一樓超過B公尺，二樓以上超過C公尺，可視為另一場所，請問前述A、B、C分別為何？', '["6，6，8", "6，6，10", "8，6，8", "8，8，15"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
